var e=[{id:`L2_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`젠장, 하필 이런 때에 침식사태라니. 지원을 기대할 수 있긴 한 건가?`,JPN:`くそ、よりによってこんな時に侵食事態なんて。支援なんてしてくれるのか？`,ENG:`Damn it, another Corruption disaster?! I don’t think there’s going to be any backup...`,TWN:`可惡！偏偏挑這種時候發生侵蝕事件，那還會有人來支援嗎？`},stage:{bg:`HIGHWAY_NORMAL`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`지휘차량이 전복됐다! 경로를 수정해!`,JPN:`指揮車両が転覆した！　経路を修正しろ！`,ENG:`Vehicle down! Change routes!`,TWN:`指揮車翻覆！修正路線！`},stage:{bg:`HIGHWAY_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`앞 교차로에서 수송차를 셋으로 나눠서 움직인다. 놈들의 시선을 분산시켜!`,JPN:`この先の交差路で輸送車を三つに分けて動く。やつらの視線を分散させろ！`,ENG:`We divide into three groups at the next intersection. Distract the enemies!`,TWN:`在前面的岔路車隊分三路行駛！分散敵人的注意！`},stage:{bg:`HIGHWAY_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DRIVER_NPC_ALPHA_NULL`,text:{KOREA:`이봐. 우리 쪽 꼬리는 어때?`,JPN:`おい。後ろどうだ？`,ENG:`Hey. How’s the trail behind us?`,TWN:`後面情況如何？`},stage:{bg:`VEHICLE`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`다행히 쫓아오지 않는 것 같군.`,JPN:`幸い付いてきてはいないようだな。`,ENG:`I don’t think they’re following us.`,TWN:`幸好沒追上來的樣子。`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`DRIVER_NPC_ALPHA_NULL`,text:{KOREA:`하하…… 그럼 따돌린 건가?`,JPN:`はは……じゃあ、うまく撒いたのか？`,ENG:`Ha ha... I guess we got away.`,TWN:`呼……那要掉頭嗎？`},stage:{bg:`VEHICLE`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`쿨럭쿨럭……`,JPN:`ゲホゲホッ……`,ENG:`*Cough!* *Cough!*`,TWN:`咳咳咳……`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CONVOY_NPC_SHIELD_NULL`,text:{KOREA:`C컨테이너! 무슨 일이지? 교전인가?`,JPN:`Cコンテナ！　どうした？　交戦か？`,ENG:`Container C! What’s going on? Any enemy interaction?`,TWN:`C車！發生什麼事？雙方交火嗎？`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_SHIELD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`그…… 그게……`,JPN:`そ……それが……`,ENG:`I-I...`,TWN:`車……車子……`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_SHIELD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`차량이 갑자기 반으로 갈라졌습니다.`,JPN:`車両がいきなり半分に割れました。`,ENG:`The vehicle got cut in half.`,TWN:`車子突然斷成二截。`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_SHIELD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CONVOY_NPC_SHIELD_NULL`,text:{KOREA:`……뭐라고? 죄수는 어떻게 됐지? 어서 상태 확인해!`,JPN:`……何だと？　囚人はどうなった？　急いで状態を確認しろ！`,ENG:`...What? What happened to the prisoner? Go see him now!`,TWN:`……你說什麼？那犯人情況如何？趕快確認！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_SHIELD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`지, 지금 확인해보겠습니다!`,JPN:`い、今確認してみます！`,ENG:`Y-yes sir, right away...!`,TWN:`是…是的，馬上確認！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_SHIELD_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`CONVOY_NPC_SHIELD_NULL`,text:{KOREA:`이보게! 어떻게 됐지? 죄수가 다치기라도 했나?`,JPN:`おい！　どうなった？　囚人が怪我でもしたのか？`,ENG:`So? How is he? Is he hurt?`,TWN:`喂！怎麼樣？犯人有受傷嗎？`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`……사라졌어요.`,JPN:`……消えました。`,ENG:`...He’s gone.`,TWN:`……不見了。`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`CONVOY_NPC_RIFLE_NULL`,text:{KOREA:`죄수가 보이지 않습니다!`,JPN:`囚人が見あたりません！`,ENG:`We lost him!`,TWN:`犯人不見了！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`CONVOY_NPC_RIFLE_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};